  ('medical-tech-moex-19981', 'medical-tech', 'medical-tech-moex-094-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '蜘蛛網膜下腔出血（subarachnoid hemorrhage）主要病因為： 腦缺氧及血管栓塞    漿果型動脈瘤（berry aneurysm）破裂 水腦（hydrocephalus）    腦震盪（concussion）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:13+00:00", "source_pdf_sha1": "8e438fc0348b", "answer_pdf_sha1": "a94d98be0292", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 72, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-19982', 'medical-tech', 'medical-tech-moex-094-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '進行性運動障礙，行動僵硬，緩慢，震顫，腦部黑質退化，是為： 巴金森氏症（Parkinson’s disease）  運動神經元疾病（motor neuron disease） 漢亭頓氏症（Huntington’s disease）  阿茲海默症（Alzheimer’s disease）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:13+00:00", "source_pdf_sha1": "8e438fc0348b", "answer_pdf_sha1": "a94d98be0292", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 73, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-19983', 'medical-tech', 'medical-tech-moex-094-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '庫欣氏症（Cushing’s syndrome）的主要病因是： 腦下垂體過度分泌腎上腺皮質激素（ACTH）  甲狀腺機能亢進 副甲狀腺機能亢進    腎上腺皮質機能不足', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:13+00:00", "source_pdf_sha1": "8e438fc0348b", "answer_pdf_sha1": "a94d98be0292", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 74, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-19984', 'medical-tech', 'medical-tech-moex-094-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '有關Type I 糖尿病的描述，何者為非？ 為自體免疫反應的結果    會發生蘭氏小島發炎（insulitis） 病人血糖上升    病人血中胰島素（insulin）上升', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:13+00:00", "source_pdf_sha1": "8e438fc0348b", "answer_pdf_sha1": "a94d98be0292", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 75, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
